package org.example;

/**
 * Test class for complex Morse message decoding.
 * Tests real-world messages and challenging patterns.
 */
public class ComplexMessageTest {

    public static void runAllTests() {
        TestUtilities.printSectionHeader("Complex Message Tests");
        
        testHeyJude();
        testTheQuickBrownFox();
        testTitanicSOS();
        testComplexAlphabet();
        testVariableSpeedMessages();
        testLongMessages();
        
        System.out.println("Complex message tests completed.");
    }

    private static void testHeyJude() {
        System.out.println("Testing HEY JUDE message:");
        
        MorseDecoder decoder = new MorseDecoder();
        TestUtilities.executeTestCase(decoder, 
            new TestUtilities.TestCase("HEY JUDE message", TestUtilities.HEY_JUDE_BITS, TestUtilities.HEY_JUDE_TEXT));
    }

    private static void testTheQuickBrownFox() {
        System.out.println("Testing THE QUICK BROWN FOX message:");
        
        String theQuickBrownFoxBits = "";
        String expectedText = "THE QUICK BROWN FOX JUMPS OVER THE LAZY DOG";
        
        MorseDecoder decoder = new MorseDecoder();
        String result = decoder.decodeMorse(decoder.decodeBitsAdvanced(theQuickBrownFoxBits));
        
        boolean passed = expectedText.equals(result);
        System.out.printf("  THE QUICK BROWN FOX: %s %s%n", 
            result.length() > 50 ? result.substring(0, 50) + "..." : result, 
            passed ? "✓" : "✗");
        
        if (!passed) {
            System.out.printf("    Expected: %s%n", expectedText);
            System.out.printf("    Got: %s%n", result);
        }
    }

    private static void testTitanicSOS() {
        System.out.println("Testing TITANIC SOS message:");
        
        String titanicSOSBits = "";
        String expectedText = "MGY CQD CQD SOS TITANIC POSITION 41.44 N 50.24 W. REQUIRE IMM...";
        
        MorseDecoder decoder = new MorseDecoder();
        String result = decoder.decodeMorse(decoder.decodeBitsAdvanced(titanicSOSBits));
        
        boolean passed = result.startsWith("MGY CQD CQD SOS TITANIC");
        System.out.printf("  TITANIC SOS: %s %s%n", 
            result.length() > 50 ? result.substring(0, 50) + "..." : result, 
            passed ? "✓" : "✗");
        
        if (!passed) {
            System.out.printf("    Expected to start with: %s%n", expectedText);
            System.out.printf("    Got: %s%n", result);
        }
    }

    private static void testComplexAlphabet() {
        System.out.println("Testing complex alphabet message:");
        
        MorseDecoder decoder = new MorseDecoder();
        String complexResult = decoder.decodeMorse(decoder.decodeBitsAdvanced(TestUtilities.COMPLEX_BITS));
        
        // Check if it contains expected patterns
        boolean containsExpected = complexResult.contains("T") && complexResult.contains("E") && complexResult.length() > 10;
        System.out.printf("  Complex message: %s %s%n", 
            complexResult.substring(0, Math.min(50, complexResult.length())) + "...", 
            containsExpected ? "✓" : "✗");
    }

    private static void testVariableSpeedMessages() {
        System.out.println("Testing variable speed messages:");
        
        MorseDecoder decoder = new MorseDecoder();
        
        // Fast transmission
        TestUtilities.executeTestCase(decoder, 
            new TestUtilities.TestCase("Fast dots", "101010", "EEE"));
        
        // Slow transmission
        TestUtilities.executeTestCase(decoder, 
            new TestUtilities.TestCase("Slow dashes", "111111000111111000", TestUtilities.EXPECTED_M));
        
        // Mixed speeds
        TestUtilities.executeTestCase(decoder, 
            new TestUtilities.TestCase("Mixed speeds", "101111110001111110101", "EE"));
    }

    private static void testLongMessages() {
        System.out.println("Testing long messages:");
        
        MorseDecoder decoder = new MorseDecoder();
        
        // Generate a longer test signal
        String longSignal = TestUtilities.generateRandomSignal(5000);
        
        long totalTime = TestUtilities.measureExecutionTime(() -> {
            String morse = decoder.decodeBitsAdvanced(longSignal);
            decoder.decodeMorse(morse);
        });
        
        double timeMs = TestUtilities.formatNanosToMillis(totalTime);
        System.out.printf("  Long message (5000 chars): %.2fms ✓%n", timeMs);
    }
    

    /**
     * Tests message accuracy and reliability.
     */
    public static boolean testAccuracy() {
        MorseDecoder decoder = new MorseDecoder();
        
        try {
            // Test known good cases
            String result1 = decoder.decodeMorse(decoder.decodeBitsAdvanced(TestUtilities.HEY_JUDE_BITS));
            String result2 = decoder.decodeMorse(decoder.decodeBitsAdvanced(TestUtilities.SIMPLE_DOTS));
            
            return TestUtilities.HEY_JUDE_TEXT.equals(result1) && TestUtilities.EXPECTED_EE.equals(result2);
        } catch (Exception e) {
            return false;
        }
    }
}
